{
var angleDeg = GetFloat(parameters, "angle", 45f);
        // Density is an integer slider (2..8) to guarantee seamless tiling.
        var density = Math.Max(0.01f, (float)GetInt(parameters, "density", 5));
        var width = Math.Clamp(GetFloat(parameters, "width", 0.2f), 0.001f, 2f);
        // Noise removed: background noise is not desired for this node.
        var brightness = GetFloat(parameters, "brightness", 0f);
        var contrast = GetFloat(parameters, "contrast", 0f);
        var invert = GetBool(parameters, "invert", false);

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);

        var angle = angleDeg * MathF.PI / 180f;
        var cosA = MathF.Cos(angle);
        var sinA = MathF.Sin(angle);

        // Width parameter controls the apparent size of each fiber blob relative to spacing.
        var safeWidth = MathF.Max(0.0005f, width);

        buffer.ParallelForEachPixel((x, y) =>
        {
            // normalized coordinates centered at 0
            var nx = x / (float)size - 0.5f;
            var ny = y / (float)size - 0.5f;

            // rotate coordinates so fibers run along the rotated Y axis
            var rx = nx * cosA - ny * sinA;
            var ry = nx * sinA + ny * cosA;

            // Repeat along the image X axis so each element's center stays on
            // the same horizontal line (y = 0 in normalized coords). We still
            // rotate the element shape itself by `angle` so highlights are
            // slanted while their centers remain aligned horizontally.
            var pos = nx * density; // repeat coordinate along image X
            var nearest = MathF.Round(pos);
            var d = pos - nearest; // signed distance in repeat units (longitudinal)

            // Build contributions from several neighboring repeat centers so a
            // rotated element that extends beyond its primary cell isn't
            // visually clipped. We evaluate nearby centers (±2) and take the
            // maximum contribution.
            var localPerp = ny * density;

            // Separate longitudinal/perpendicular sigmas (in repeat units).
            var sigmaLong = MathF.Max(0.001f, safeWidth * 0.6f);
            var sigmaPerp = MathF.Max(0.001f, safeWidth * 1.4f);

            var v = 0f;
            // check several neighbors to avoid clipping when the rotated
            // shape crosses cell boundaries (tileable wrap-around)
            for (int oi = -2; oi <= 2; ++oi)
            {
                var center = nearest + oi;
                var localLong = pos - center; // signed distance to this center

                // Rotate the local vector so the element shape is oriented by angle
                var rLong = localLong * cosA - localPerp * sinA;
                var rPerp = localLong * sinA + localPerp * cosA;

                var ndLong = rLong / sigmaLong;
                var ndPerp = rPerp / sigmaPerp;

                var soft = MathF.Exp(-0.5f * (ndLong * ndLong + ndPerp * ndPerp));
                var core = MathF.Exp(-0.5f * ((ndLong * 0.5f) * (ndLong * 0.5f) + (ndPerp * 0.5f) * (ndPerp * 0.5f)));
                // Adapt core weight based on element width so wider fibers don't produce
                // excessively large saturated regions. Wider shapes get a smaller core
                // contribution and stronger soft (diffuse) contribution. Reduce the
                // core weight more aggressively for wide elements to avoid large
                // flat white plateaus.
                var widthFactor = Math.Clamp((safeWidth - 0.001f) / 1.5f, 0f, 1f);
                var coreWeight = 0.35f * (1f - 0.6f * widthFactor);
                var softWeight = 0.75f * (1f - 0.12f * widthFactor);
                var contrib = Math.Clamp(soft * softWeight + core * coreWeight, 0f, 1f);
                if (contrib > v) v = contrib;
            }

            // background noise removed

            // Soften the very brightest highlights so they blend smoothly with surrounding grays.
            // Use a small lerp toward a slightly compressed curve (pow > 1) to reduce harsh "cut" edges.
            // Increase softening to reduce the absolute peak intensity and smooth transition.
            // Adaptive softening: stronger softening for wider elements so the
            // brightest area doesn't become a large flat white plateau.
            var widthFactorGlobal = Math.Clamp((safeWidth - 0.001f) / 1.5f, 0f, 1f);
            // Stronger base softening so peaks are reduced earlier; additional
            // softening scales with width to avoid wide flat whites.
            var peakSoftenBase = 0.45f;
            var peakSoften = peakSoftenBase + 0.5f * widthFactorGlobal; // 0.45 .. ~0.95
            var powBase = 1.25f;
            var powExp = powBase + 0.9f * widthFactorGlobal; // 1.25 .. ~2.15
            // Manual lerp because MathF.Lerp is not available in this target
            v = v * (1f - peakSoften) + MathF.Pow(v, powExp) * peakSoften;

            // Contrast & brightness
            if (MathF.Abs(contrast) > 0.0001f)
            {
                var factor = 1f + contrast;
                v = (v - 0.5f) * factor + 0.5f;
            }

            v += brightness;
            v = Math.Clamp(v, 0f, 1f);
            // Soft knee to avoid a hard "cut" at the top of the curve. The knee
            // threshold lowers for wider elements to keep large highlights smooth.
            // Soft knee to avoid a hard "cut" at the top of the curve. Lower the
            // knee threshold for wider elements and use a width-dependent ease
            // exponent so the shoulder becomes smoother as width increases.
            var kneeStart = 0.88f - 0.25f * widthFactorGlobal; // e.g. 0.88 .. 0.63
            if (v > kneeStart)
            {
                var t = (v - kneeStart) / (1f - kneeStart);
                // Use a stronger ease-out for wider elements to produce a gradual
                // approach to 1.0 instead of a hard plateau.
                var easeExp = 1f + 2f * widthFactorGlobal; // 1 .. 3
                var eased = 1f - MathF.Pow(1f - t, easeExp);
                v = kneeStart + (1f - kneeStart) * eased;
            }
            if (invert) v = 1f - v;

            buffer.SetPixel(x, y, v, v, v, 1f);
        });

        return buffer;
}
